.form_main{
	height: 500px;
	width:400px;
	margin: 50px auto;
	background: linear-gradient(teal, green);
	display:flex;
	justify-content: center;
	align-items: center;
	transition: all linear .3s;

}

.form_main:hover{
	box-shadow: 1px 1px 20px red;
	transition: all linear .3s;
	border-radius: 100px;
}

.form_main form input{
	padding: 10px 50px 10px 5px;
	background: transparent;
	border: none;
	outline:none;
	border: 2px solid white;
	margin-top: 10px;
	border-radius: 100px;
	display:flex;
	justify-content: center;
	align-items: center;


}

.form_main form label{
	color:white;
	margin: 10px auto;
}

.form_main form input::placeholder{
	color:lightgray;
	align-items: center;
	display:flex;
	justify-content: center;
	align-items: center;
}

.form_main form button{
	margin: 10px auto;
	padding: 10px 50px 10px 5px;
	border-radius: 100px;
	display:flex;
	justify-content: center;
	align-items: center;
	transition: all linear .3s;
}

.form_main form button:hover{
	box-shadow: 1px 1px 20px yellow;
	transition: all linear .3s;
	border-radius: 100px;

